const customers = $input.all().map(i => i.json);
const trigger = $('Analyze Weather Conditions').first().json;
const type = trigger.type;
const subject = trigger.subject;
const temp = trigger.current_temp;
const conditions = trigger.conditions;

const serviceBlocks = {
  snow: {
    headline: 'Snow Is Here — We\'ve Got You Covered',
    body: 'Madison is getting hit with snow and your driveway and walkways need clearing. TotalGuard crews are mobilizing now — book your snow removal before the rush.',
    cta: 'Book Snow Removal',
    ctaUrl: 'https://tgyardcare.com/contact'
  },
  heatwave: {
    headline: 'Extreme Heat Alert — Protect Your Lawn',
    body: 'With temperatures above ' + Math.round(temp) + 'F, your lawn is under serious heat stress. Our lawn care team can help it survive with proper mowing, watering guidance, and treatment.',
    cta: 'Schedule Lawn Care',
    ctaUrl: 'https://tgyardcare.com/contact'
  },
  storm: {
    headline: 'Storm Cleanup — We\'re Ready to Help',
    body: 'Severe weather has hit Madison with ' + Math.round(trigger.wind_speed) + ' mph winds. If you have storm damage — fallen branches, debris, or damaged landscaping — TotalGuard offers same-day cleanup for existing customers.',
    cta: 'Request Storm Cleanup',
    ctaUrl: 'https://tgyardcare.com/contact'
  },
  freeze: {
    headline: 'Freeze Warning — Protect Your Landscaping',
    body: 'Temperatures are dropping to ' + Math.round(temp) + 'F in Madison. Protect your plants, irrigation, and landscape investment. We can winterize your property today.',
    cta: 'Schedule Winterization',
    ctaUrl: 'https://tgyardcare.com/contact'
  }
};

const block = serviceBlocks[type] || serviceBlocks.storm;

const results = [];
for (const c of customers) {
  if (!c.email) continue;
  const firstName = c.first_name || 'Neighbor';

  const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"></head><body style="margin:0;padding:0;background-color:#1a1a2e;font-family:Arial,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#1a1a2e;padding:20px 0;"><tr><td align="center"><table width="600" cellpadding="0" cellspacing="0" style="background-color:#16213e;border-radius:12px;overflow:hidden;"><tr><td style="background:linear-gradient(135deg,#0f3d0f,#1a5c1a);padding:30px;text-align:center;"><h1 style="color:#f5c518;margin:0;font-size:28px;">TotalGuard</h1><p style="color:#a8d5a8;margin:5px 0 0;font-size:14px;">Yard Care &amp; Snow Removal</p></td></tr><tr><td style="padding:30px;"><h2 style="color:#f5c518;margin:0 0 15px;font-size:22px;">${block.headline}</h2><p style="color:#e0e0e0;font-size:16px;line-height:1.6;margin:0 0 10px;">Hi ${firstName},</p><p style="color:#e0e0e0;font-size:16px;line-height:1.6;margin:0 0 20px;">${block.body}</p><table cellpadding="0" cellspacing="0" style="margin:25px auto;"><tr><td style="background:linear-gradient(135deg,#f5c518,#d4a813);border-radius:8px;padding:14px 32px;"><a href="${block.ctaUrl}" style="color:#1a1a2e;text-decoration:none;font-weight:bold;font-size:16px;">${block.cta}</a></td></tr></table><p style="color:#888;font-size:13px;margin:20px 0 0;">Current conditions: ${conditions} | ${Math.round(temp)}F</p></td></tr><tr><td style="padding:20px 30px;border-top:1px solid #2a2a4a;"><p style="color:#666;font-size:12px;margin:0;text-align:center;">TotalGuard Yard Care | Madison, WI | (608) 535-6057<br><a href="https://tgyardcare.com" style="color:#a8d5a8;">tgyardcare.com</a></p></td></tr></table></td></tr></table></body></html>`;

  results.push({
    json: {
      to_email: c.email,
      subject: subject,
      html_body: html,
      workflow_name: 'TG-56',
      email_type: 'weather_campaign_' + type,
      lead_id: c.id,
      customer_name: firstName
    }
  });
}

return results;
